# Configure AWS provider for account 029037611564 and region eu-north-1.
# Credentials: default chain (AWS_ACCESS_KEY_ID/AWS_SECRET_ACCESS_KEY, or ~/.aws/credentials [default]).
# If you use a named profile, add: profile = "your-profile-name" (do not use account ID as profile name).

terraform {
  required_version = ">= 1.0"

  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = ">= 4.0"
    }
  }
}

provider "aws" {
  region = "eu-north-1"
}

# Enforce SSL-only S3 requests - Action: 07ab40cb-e2c0-45c6-b124-f109e9a7c072
data "aws_iam_policy_document" "security_autopilot_ssl_enforcement" {
  statement {
    sid    = "DenyInsecureTransport"
    effect = "Deny"
    principals {
      type        = "*"
      identifiers = ["*"]
    }
    actions = ["s3:*"]
    resources = [
      "arn:aws:s3:::phase2-live-c3-s35-224523z-029037611564",
      "arn:aws:s3:::phase2-live-c3-s35-224523z-029037611564/*",
    ]
    condition {
      test     = "Bool"
      variable = "aws:SecureTransport"
      values   = ["false"]
    }
  }

}

resource "aws_s3_bucket_policy" "security_autopilot" {
  bucket = "phase2-live-c3-s35-224523z-029037611564"
  policy = data.aws_iam_policy_document.security_autopilot_ssl_enforcement.json
}
